#page-container {
	overflow-x: hidden;
}

a.et_pb_button.et_pb_pricing_table_button {
    background: #303030 !important;
    border-color: #303030 !important;
}

body div.et_pb_section.et_pb_section_0_tb_footer {
    background-image: linear-gradient(135deg, #303030cf 73%, rgb(0 0 0 / 80%) 100%, #303030 100%), url(https://anfatraining.com/wp-content/uploads/2022/08/JPEG-bild-scaled.jpeg) !important;
}

@media screen and (max-width:980px) {
	    .home .anfa-prices-row,.home .anfa-services-section,.home .anfa-image-gallery .et_pb_gallery_items {
        display: block;
        width: 100%;
	}
    .home .anfa-prices-row .et_pb_column,.home .anfa-services-section .et_pb_row,.home .et_pb_column .anfa-image-gallery .et_pb_gallery_items .et_pb_gallery_item {
        margin-bottom: 25px;
        scroll-snap-align: start;
        display: block !important;
			text-align: center;
    }
.et_pb_row_0_tb_footer.et_pb_row .et_pb_column {
		align-items:center;
	}
.home .et_pb_column .anfa-image-gallery .et_pb_gallery_items .et_pb_gallery_item {

        text-align: center;
        width: 48%;
        padding: 1px 2%;
    }
}

@media screen and (max-width:768px) {
	.home .anfa-landing-row {
        display: block;
    }

}
@media screen and (max-width:480px) {
	.home .et_pb_column .anfa-image-gallery .et_pb_gallery_items .et_pb_gallery_item {

        text-align: center;
        width: 100%;
        padding: 0;
    }


}

wp:postmeta.wp:meta_value:
@media screen and (max-width: 980px) {
  .anfa-image-gallery .et_pb_gallery_items {
    display: grid;
    grid-auto-flow: column;
    grid-template-columns: repeat(4, 90%);
    overflow-x: auto;
    min-height: 100%;
    scroll-snap-type: x mandatory;
  }
  .et_pb_column .anfa-image-gallery .et_pb_gallery_items .et_pb_gallery_item {
    margin: 10px 0;
    width: 100%;
    scroll-snap-align: start;
  }

  .anfa-prices-row {
    display: grid;
    grid-auto-flow: column;
    grid-template-columns: repeat(3, 60%);
    overflow-x: auto;
    width: 90%;
    grid-gap: 2rem;
    scroll-snap-type: x mandatory;
  }
  .anfa-prices-row .et_pb_column {
    margin-bottom: 0;
    scroll-snap-align: start;
  }
  .anfa-landing-row {
    display: flex;
  }
  .anfa-services-section {
    display: grid;
    grid-auto-flow: column;
    grid-template-columns: repeat(8, 80%);
    overflow-x: auto;
    scroll-snap-type: x mandatory;
  }
  .anfa-services-section .et_pb_row {
    width: 90%;
    scroll-snap-align: center;
  }
}
@media screen and (max-width: 479px) {
  .anfa-prices-row {
    grid-template-columns: repeat(3, 85%);
  }
  .anfa-landing-row {
    display: grid;
    grid-auto-flow: column;
    grid-template-columns: repeat(3, 80%);
    overflow-x: auto;
    scroll-snap-type: x mandatory;
  }
  .anfa-landing-row .et_pb_column {
    scroll-snap-align: center;
  }
}
.et_pb_pricing_table_wrap {
flex-direction: column;
  min-height: 100%;
}

.et_prices_table, .et_prices_table .et_pb_gutters2 .et_pb_column_1_3, .et_pb_gutters2.et_pb_row .et_pb_column_1_3 {
  display: flex;
}
.et_pb_pricing_table {
    justify-content: space-between;
    display: flex;
    flex-direction: column;
}

@media screen and (max-width: 980px) {
  .anfa-order-col {
    display: flex;
    flex-direction: column-reverse;
  }

  .snappy-scroll {
    scroll-snap-type: x mandatory;
  }
  .snappy-scroll div {
    scroll-snap-align: center;
  }

  .anfa-training-prices-row {
    display: flex;
    gap: 0.4rem;
    width: 100%;
  }
  .anfa-hr-scroll .et_pb_row {
    display: flex;
    flex-direction: row;
  }
  .anfa-hr-scroll .et_pb_row .et_pb_column {
    width: 50%;
  }
}
@media screen and (max-width: 479px) {
  .anfa-hr-scroll {
    display: grid;
    grid-auto-flow: column;
    grid-template-columns: repeat(7, 90%);
    overflow-x: auto;
    gap: 2rem;
	}
  .anfa-hr-scroll .et_pb_row {
    display: unset;
  }
  .anfa-hr-scroll .et_pb_row .et_pb_column {
    width: unset;
  }
  .anfa-hr-scroll .et_pb_column {
    height: 183px;
    display: flex;
    justify-content: center;
    flex-direction: column;
    padding: 10% 0;
	}
  .anfa-training-prices-row {
    display: grid;
    grid-auto-flow: column;
    overflow-x: auto;
    grid-template-columns: repeat(3, 90%);
  }
}
.anfa-training-prices-row .et_pb_column, .anfa-training-prices-row .et_pb_column .et_pb_pricing, .anfa-training-prices-row .et_pb_column .et_pb_pricing .et_pb_pricing_table_wrap, .anfa-training-prices-row .et_pb_column .et_pb_pricing .et_pb_pricing_table_wrap .et_pb_pricing_table {
  display: flex;
  flex-direction: column;
  min-height: 100%;
  justify-content: space-between;
  margin-bottom: 0 !important;
}

.et_pb_pricing_table_wrap {
flex-direction: column;
