}

.et_prices_table, .et_prices_table .et_pb_gutters2 .et_pb_column_1_3, .et_pb_gutters2.et_pb_row .et_pb_column_1_3 {
  display: flex;
}
.et_pb_pricing_table {
    justify-content: space-between;
    display: flex;
    flex-direction: column;
}

.et_pb_pricing_table_wrap {
flex-direction: column;
